#' JASP Enhanced Logistic Regression
#'
#' jamovi-native shell for the JASP logistic regression analysis.
#' @param data .
#' @param dependent .
#' @param covariates .
#' @param factors .
#' @param modelFit .
#' @param classification .
#' @param apaReport .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$status} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$about} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
enhancedLogisticRegression <- function(
    data,
    dependent,
    covariates,
    factors,
    modelFit = TRUE,
    classification = TRUE,
    apaReport = TRUE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("enhancedLogisticRegression requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dependent)) dependent <- jmvcore::resolveQuo(jmvcore::enquo(dependent))
    if ( ! missing(covariates)) covariates <- jmvcore::resolveQuo(jmvcore::enquo(covariates))
    if ( ! missing(factors)) factors <- jmvcore::resolveQuo(jmvcore::enquo(factors))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dependent), dependent, NULL),
            `if`( ! missing(covariates), covariates, NULL),
            `if`( ! missing(factors), factors, NULL))

    for (v in dependent) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in factors) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- enhancedLogisticRegressionOptions$new(
        dependent = dependent,
        covariates = covariates,
        factors = factors,
        modelFit = modelFit,
        classification = classification,
        apaReport = apaReport)

    analysis <- enhancedLogisticRegressionClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

